    where q.exam_source = 'AI-generated-board-seed'
      and q.board_specialty = 'surgery'
      and q.scenario = 'Basic science: surgical decision-making + evidence-based medicine

คำถาม: evidence-based surgery + clinical practice guidelines'
  );

